      "code": "<usereventscript scriptid=\"customscriptcustrecord_sync_invc_ns_sf\">\n  <description></description>\n  <isinactive>F</isinactive>\n  <name>CSS UE sync_invc_NS_SF</name>\n  <notifyadmins>F</notifyadmins>\n  <notifyemails></notifyemails>\n  <notifyowner>T</notifyowner>\n  <notifyuser>F</notifyuser>\n  <scriptfile>[/SuiteScripts/c106397_Sync_Invoice_NS_to_SF.js]</scriptfile>\n  <scriptdeployments>\n    <scriptdeployment scriptid=\"customdeploy_sync_invc_ns_sf\">\n      <allemployees>T</allemployees>\n      <alllocalizationcontexts>T</alllocalizationcontexts>\n      <allpartners>F</allpartners>\n      <allroles>T</allroles>\n      <audslctrole>CUSTOMER_CENTER|EMPLOYEE_CENTER|NETSUITE_SUPPORT_CENTER|NETSUITE_SUPPORT_CENTER__BASIC|PARTNER_CENTER|VENDOR_CENTER</audslctrole>\n      <audsubsidiary>[ACCOUNT_SPECIFIC_VALUE]|[ACCOUNT_SPECIFIC_VALUE]|[ACCOUNT_SPECIFIC_VALUE]|[ACCOUNT_SPECIFIC_VALUE]|[ACCOUNT_SPECIFIC_VALUE]|[ACCOUNT_SPECIFIC_VALUE]</audsubsidiary>\n      <eventtype></eventtype>\n      <executioncontext>ACTION|ADVANCEDREVREC|BANKCONNECTIVITY|BANKSTATEMENTPARSER|BUNDLEINSTALLATION|CLIENT|CONSOLRATEADJUSTOR|CSVIMPORT|CUSTOMGLLINES|CUSTOMMASSUPDATE|DATASETBUILDER|DEBUGGER|EMAILCAPTURE|FICONNECTIVITY|FIPARSER|MAPREDUCE|OCRPLUGIN|OTHER|PAYMENTGATEWAY|PAYMENTPOSTBACK|PLATFORMEXTENSION|PORTLET|PROMOTIONS|RECORDACTION|RESTLET|RESTWEBSERVICES|SCHEDULED|SDFINSTALLATION|SHIPPINGPARTNERS|SUITELET|TAXCALCULATION|USEREVENT|USERINTERFACE|WEBSERVICES|WORKBOOKBUILDER|WORKFLOW</executioncontext>\n      <isdeployed>T</isdeployed>\n      <loglevel>DEBUG</loglevel>\n      <recordtype>INVOICE</recordtype>\n      <runasrole>ADMINISTRATOR</runasrole>\n      <status>RELEASED</status>\n    </scriptdeployment>\n  </scriptdeployments>\n</usereventscript>"
